const t="product-detail.html";function n(t=window.location.pathname){const n=t.split("?")[0].split("#")[0];return(n.endsWith("/")?n:n.substring(0,n.lastIndexOf("/")+1))||"/"}export function isStandaloneDetailPage(n=window.location.pathname){return n.endsWith(`/${t}`)||n.endsWith(t)}export function getProductDetailUrl(e,o=window.location.origin,i=window.location.pathname){return`${o}${n(i)}${t}?id=${encodeURIComponent(e)}`}export function getLegacyDetailUrl(t){return`${n()}index.html?p=${encodeURIComponent(t)}`}export function getProductIdFromSearch(t=window.location.search){const n=new URLSearchParams(t);return n.get("id")||n.get("p")}